// Mensagem direta do cliente (pt-BR). Números via toLocaleString('pt-BR').
const j = $json
const fmt = (n) => Number(n).toLocaleString('pt-BR')
const mensagem =
  `🎯 *Oportunidade pra você!*\n\n` +
  `Você tem *${fmt(j.saldo)} ${j.origem}* e saiu *${fmt(j.bonus_numeric)}% de bônus* pra *${j.destino}* — daria *~${fmt(j.resultado)} ${j.destino}*.\n\n` +
  `Confira as regras no site do programa antes de transferir.`
return { json: { ...j, mensagem } }
